SELECT producer_id, name
FROM producers
WHERE region_id = 1;

SELECT regions.region_name, producers.name
FROM regions
JOIN producers ON regions.region_id = producers.region_id;

SELECT well_id, COUNT(*) as activity_count
FROM drilling_activities
GROUP BY well_id;

SELECT region_id, COUNT(DISTINCT well_type) AS unique_well_types_count
FROM wells
GROUP BY region_id;
